#!/usr/bin/env python3
"""CI validation for metric naming and tagging standards.
Usage: python validate_metrics.py metrics/manifest.yaml"""
import sys, re, yaml
from pathlib import Path

NAMESPACES = {"ai", "infra", "http", "db"}
UNIT_SUFFIXES = {"_seconds", "_bytes", "_total", "_usd", "_ratio"}
AGGR_SUFFIXES = {"counter", "gauge", "histogram", "summary"}
FORBIDDEN_TAGS = {"user_id", "conversation_id", "user_prompt", "session_id", "request_body"}
MAX_CARDINALITY = {
    "gen_ai.request.model": 50,
    "tool_name": 100,
    "agent_id": 1000,
    "error_type": 20,
}

NAME_RE = re.compile(r'^[a-z][a-z0-9]*(?:\.[a-z][a-z0-9_]*)+$')

def validate_manifest(path: str) -> list[str]:
    errors = []
    manifest = yaml.safe_load(Path(path).read_text())

    for metric in manifest.get("metrics", []):
        name: str = metric["name"]
        tags: list[str] = metric.get("tags", [])
        cardinality: dict = metric.get("cardinality_budget", {})

        # 1. Name format
        if not NAME_RE.match(name):
            errors.append(f"{name}: name must match {NAME_RE.pattern}")
            continue

        # 2. Must start with a registered namespace
        ns = name.split(".")[0]
        if ns not in NAMESPACES:
            errors.append(f"{name}: unknown namespace '{ns}', allowed: {NAMESPACES}")

        # 3. Must end with a known aggregation type
        if not any(name.endswith(a) for a in AGGR_SUFFIXES):
            errors.append(f"{name}: must end with one of {AGGR_SUFFIXES}")

        # 4. Unit suffix before aggregation type
        base = re.sub(r'\.(counter|gauge|histogram|summary)$', '', name)
        if not any(base.endswith(u) for u in UNIT_SUFFIXES):
            errors.append(f"{name}: unit suffix missing; expected one of {UNIT_SUFFIXES}")

        # 5. No forbidden tags
        for tag in tags:
            if tag in FORBIDDEN_TAGS:
                errors.append(f"{name}: forbidden tag '{tag}' — use traces or logs for high-cardinality data")

        # 6. Cardinality budget declared for optional tags
        for tag in tags:
            if tag in MAX_CARDINALITY:
                budget = cardinality.get(tag)
                if budget is None:
                    errors.append(f"{name}: tag '{tag}' requires cardinality_budget declaration")
                elif budget > MAX_CARDINALITY[tag]:
                    errors.append(
                        f"{name}: tag '{tag}' budget {budget} exceeds max {MAX_CARDINALITY[tag]}"
                    )

    return errors

if __name__ == "__main__":
    errs = validate_manifest(sys.argv[1])
    for e in errs:
        print(f"ERROR: {e}")
    sys.exit(1 if errs else 0)
